func (v RolloutValue) ToObjectValue(ctx context.Context) (basetypes.ObjectValue, diag.Diagnostics) {
	var diags diag.Diagnostics

	var variantSplitsVal basetypes.MapValue
	switch {
	case v.VariantSplits.IsUnknown():
		variantSplitsVal = types.MapUnknown(types.NumberType)
	case v.VariantSplits.IsNull():
		variantSplitsVal = types.MapNull(types.NumberType)
	default:
		var d diag.Diagnostics
		variantSplitsVal, d = types.MapValue(types.NumberType, v.VariantSplits.Elements())
		diags.Append(d...)
	}

	if diags.HasError() {
		return types.ObjectUnknown(map[string]attr.Type{
			"cohort_hash":        basetypes.StringType{},
			"name":               basetypes.StringType{},
			"rollout_percentage": basetypes.NumberType{},
			"variant_splits": basetypes.MapType{
				ElemType: types.NumberType,
			},
		}), diags
	}

	attributeTypes := map[string]attr.Type{
		"cohort_hash":        basetypes.StringType{},
		"name":               basetypes.StringType{},
		"rollout_percentage": basetypes.NumberType{},
		"variant_splits": basetypes.MapType{
			ElemType: types.NumberType,
		},
	}

	if v.IsNull() {
		return types.ObjectNull(attributeTypes), diags
	}

	if v.IsUnknown() {
		return types.ObjectUnknown(attributeTypes), diags
	}

	objVal, diags := types.ObjectValue(
		attributeTypes,
		map[string]attr.Value{
			"cohort_hash":        v.CohortHash,
			"name":               v.Name,
			"rollout_percentage": v.RolloutPercentage,
			"variant_splits":     variantSplitsVal,
		})

	return objVal, diags
}

func (v RolloutValue) Equal(o attr.Value) bool {
	other, ok := o.(RolloutValue)

	if !ok {
		return false
	}

	if v.state != other.state {
		return false
	}

	if v.state != attr.ValueStateKnown {
		return true
	}

	if !v.CohortHash.Equal(other.CohortHash) {
		return false
	}

	if !v.Name.Equal(other.Name) {
		return false
	}

	if !v.RolloutPercentage.Equal(other.RolloutPercentage) {
		return false
	}

	if !v.VariantSplits.Equal(other.VariantSplits) {
		return false
	}

	return true
}

